/**
 * Parse a `Retry-After` header value into milliseconds.
 *
 * Per RFC 7231 §7.1.3, the value is either:
 *   - delta-seconds (e.g. "120")
 *   - an HTTP-date (e.g. "Wed, 21 Oct 2026 07:28:00 GMT")
 *
 * Returns undefined if it can't be parsed or is in the past.
 */
export function parseRetryAfter(
  value: string | number | null | undefined,
  now: number = Date.now(),
): number | undefined {
  if (value === null || value === undefined) return undefined;

  if (typeof value === "number") {
    return value >= 0 ? value * 1000 : undefined;
  }

  const trimmed = value.trim();
  if (!trimmed) return undefined;

  // Try delta-seconds first (numeric only, optionally with decimals).
  if (/^\d+(\.\d+)?$/.test(trimmed)) {
    const seconds = parseFloat(trimmed);
    if (!Number.isFinite(seconds) || seconds < 0) return undefined;
    return Math.round(seconds * 1000);
  }

  // Otherwise parse as HTTP-date.
  const dateMs = Date.parse(trimmed);
  if (Number.isNaN(dateMs)) return undefined;

  const diff = dateMs - now;
  return diff > 0 ? diff : 0;
}

/**
 * Read a header value from various header-bag shapes that errors carry:
 *   - Headers instance (web-fetch / undici)
 *   - plain object map (axios, node-fetch v1, custom)
 *   - Map<string, string>
 *
 * Header lookup is case-insensitive.
 */
function readHeader(
  headers: unknown,
  name: string,
): string | number | undefined {
  if (!headers) return undefined;

  // Map check must come BEFORE the generic `.get` check, because Map also has a .get method.
  if (headers instanceof Map) {
    const lower = name.toLowerCase();
    for (const [k, v] of headers.entries()) {
      if (typeof k === "string" && k.toLowerCase() === lower) {
        return v as string | number;
      }
    }
    return undefined;
  }

  // Headers instance (web-fetch / undici)
  if (typeof (headers as Headers).get === "function") {
    try {
      const v = (headers as Headers).get(name);
      return v ?? undefined;
    } catch {
      // fall through
    }
  }

  // Plain object — case-insensitive scan.
  if (typeof headers === "object") {
    const obj = headers as Record<string, unknown>;
    const lower = name.toLowerCase();
    for (const k of Object.keys(obj)) {
      if (k.toLowerCase() === lower) {
        const v = obj[k];
        if (typeof v === "string" || typeof v === "number") return v;
        if (Array.isArray(v) && v.length > 0) {
          const first = v[0];
          if (typeof first === "string" || typeof first === "number")
            return first;
        }
      }
    }
  }

  return undefined;
}

/**
 * Extract a Retry-After delay (in ms) from any common error shape:
 *   - err.headers / err.response.headers
 *   - axios: err.response.headers
 *   - fetch: err.headers (when user throws the Response)
 *
 * Also supports a top-level `err.retryAfter` numeric escape hatch.
 */
export function extractRetryAfterMs(error: unknown): number | undefined {
  if (!error || typeof error !== "object") return undefined;
  const e = error as Record<string, unknown>;

  // Direct numeric escape hatch.
  if (typeof e.retryAfter === "number") {
    return e.retryAfter >= 0 ? e.retryAfter * 1000 : undefined;
  }

  const candidates: unknown[] = [
    e.headers,
    (e.response as { headers?: unknown } | undefined)?.headers,
  ];

  for (const headers of candidates) {
    const raw = readHeader(headers, "retry-after");
    if (raw !== undefined) {
      const ms = parseRetryAfter(raw);
      if (ms !== undefined) return ms;
    }
  }

  return undefined;
}
