/**
 * Backoff strategy for delay calculation between retries.
 *
 * - `exponential` — delay doubles each attempt: `delay * 2^attempt`
 * - `linear`      — delay grows linearly: `delay * (attempt + 1)`
 * - `fixed`       — same delay between every attempt
 */
export type BackoffStrategy = "exponential" | "linear" | "fixed";

/**
 * The function being retried receives an attempt context.
 *
 * @param attempt - 0-indexed attempt number (0 on first try, 1 on first retry, etc.)
 * @param signal  - AbortSignal that fires if the overall operation is aborted
 *                  or a per-attempt timeout elapses. Forward this to fetch/etc.
 */
export type RetryableFn<T> = (ctx: AttemptContext) => Promise<T> | T;

export interface AttemptContext {
  /** 0-indexed attempt number. */
  readonly attempt: number;
  /**
   * AbortSignal combining the user-provided signal and the per-attempt timeout.
   * Forward this to fetch/axios so in-flight requests are canceled on abort.
   */
  readonly signal: AbortSignal;
}

/**
 * Decides whether an error is retryable. Return `true` to retry, `false` to give up.
 * Receives the error and the current 0-indexed attempt number.
 */
export type RetryPredicate = (
  error: unknown,
  attempt: number,
) => boolean | Promise<boolean>;

/**
 * Called before each retry. Return `false` to cancel the retry and reject immediately.
 *
 * @param error   - the error that triggered the retry
 * @param attempt - 0-indexed attempt that just failed
 * @param delay   - milliseconds the engine is about to sleep before the next attempt
 */
export type OnRetryHook = (
  error: unknown,
  attempt: number,
  delay: number,
) => void | false | Promise<void | false>;

export type OnSuccessHook<T> = (
  result: T,
  attempt: number,
) => void | Promise<void>;

export type OnFailHook = (
  error: unknown,
  attempt: number,
) => void | Promise<void>;

export interface RetryOptions<T = unknown> {
  /**
   * Maximum number of retries (additional attempts after the first).
   * Total attempts = `retries + 1`. Defaults to `3`.
   */
  retries?: number;

  /**
   * Initial delay in milliseconds before the first retry. Defaults to `200`.
   */
  delay?: number;

  /**
   * Backoff strategy. Defaults to `exponential` (and is forced to exponential when `ai: true`).
   */
  backoff?: BackoffStrategy;

  /**
   * Add randomized jitter to delays to prevent thundering-herd. Defaults to `true`.
   * Uses "full jitter": `random(0, computedDelay)`.
   */
  jitter?: boolean;

  /**
   * Cap on individual delay between retries (in ms). Defaults to `30_000`.
   */
  maxDelay?: number;

  /**
   * Total time budget for the whole retry operation (in ms). When exceeded,
   * the operation rejects with the most recent error. `0` or omitted = no overall cap.
   */
  totalTimeout?: number;

  /**
   * Per-attempt timeout (in ms). When exceeded, the in-flight attempt is aborted
   * (its `signal` fires) and treated as a retryable failure.
   */
  timeout?: number;

  /**
   * AI-aware mode. When `true`:
   *   - HTTP 429, 408, 5xx and common transient network errors are retried
   *   - `Retry-After` headers (seconds and HTTP-date) are respected
   *   - exponential backoff is forced
   *   - jitter is enabled by default
   *   - default retries is bumped to `5`
   */
  ai?: boolean;

  /**
   * Custom retry predicate. Overrides the default error classification.
   */
  retry?: RetryPredicate;

  /** External AbortSignal — when it fires, retrying stops immediately. */
  signal?: AbortSignal;

  /** Fallback value (or factory) returned if all attempts fail. Suppresses the error. */
  fallback?: T | ((error: unknown) => T | Promise<T>);

  /** Hook fired before each retry. Return `false` to cancel the retry. */
  onRetry?: OnRetryHook;

  /** Hook fired on final success. */
  onSuccess?: OnSuccessHook<T>;

  /** Hook fired on final failure (after retries are exhausted or aborted). */
  onFail?: OnFailHook;
}

/**
 * Error thrown when retries are exhausted. Wraps the most recent underlying error.
 */
export class RetryError extends Error {
  readonly cause: unknown;
  readonly attempts: number;
  readonly errors: unknown[];

  constructor(message: string, errors: unknown[]) {
    super(message);
    this.name = "RetryError";
    this.errors = errors;
    this.attempts = errors.length;
    this.cause = errors[errors.length - 1];
  }
}

/** Error thrown when an attempt or the overall operation is aborted. */
export class AbortError extends Error {
  constructor(message = "Operation aborted") {
    super(message);
    this.name = "AbortError";
  }
}

/** Error thrown when a per-attempt or total timeout elapses. */
export class TimeoutError extends Error {
  constructor(message = "Operation timed out") {
    super(message);
    this.name = "TimeoutError";
  }
}
