import { AbortError } from "../types.js";

/**
 * Sleep for `ms` milliseconds. If the provided signal aborts, the sleep
 * rejects with AbortError immediately (and the timer is cleared).
 *
 * Works in Node and browsers — uses globalThis.setTimeout.
 */
export function sleep(ms: number, signal?: AbortSignal): Promise<void> {
  if (ms <= 0) {
    if (signal?.aborted) return Promise.reject(new AbortError());
    return Promise.resolve();
  }

  return new Promise((resolve, reject) => {
    if (signal?.aborted) {
      reject(new AbortError());
      return;
    }

    const timer = setTimeout(() => {
      signal?.removeEventListener("abort", onAbort);
      resolve();
    }, ms);

    const onAbort = () => {
      clearTimeout(timer);
      reject(new AbortError());
    };

    signal?.addEventListener("abort", onAbort, { once: true });
  });
}
