/**
 * Heuristic detection of retryable errors for AI / API workflows.
 *
 * We duck-type rather than depend on any HTTP client. The following shapes
 * are recognized:
 *
 *   - fetch Response errors:    err.status, err.response.status
 *   - axios:                    err.response.status, err.code
 *   - node-fetch / undici:      err.code === 'ECONNRESET' / 'ETIMEDOUT' / ...
 *   - Node net errors:          err.code, err.errno
 *   - thrown Response objects:  res.status (when user throws non-ok responses)
 *   - AbortError:               NOT retried (intentional cancellation)
 */

const RETRYABLE_STATUS = new Set([
  408, // Request Timeout
  409, // Conflict (often a retryable race in DB/AI APIs)
  425, // Too Early
  429, // Too Many Requests — the big one for rate limits
  500, // Internal Server Error
  502, // Bad Gateway
  503, // Service Unavailable
  504, // Gateway Timeout
  529, // Site Overloaded (Anthropic uses this)
]);

const RETRYABLE_NETWORK_CODES = new Set([
  "ECONNRESET",
  "ECONNREFUSED",
  "ETIMEDOUT",
  "EPIPE",
  "EAI_AGAIN",
  "ENOTFOUND",
  "ENETUNREACH",
  "EHOSTUNREACH",
  "EHOSTDOWN",
  "ECONNABORTED", // axios timeout
  "ERR_NETWORK",
  "UND_ERR_SOCKET", // undici
  "UND_ERR_CONNECT_TIMEOUT",
  "UND_ERR_HEADERS_TIMEOUT",
  "UND_ERR_BODY_TIMEOUT",
]);

/** Extract an HTTP status code from any common error shape. */
export function getStatus(error: unknown): number | undefined {
  if (!error || typeof error !== "object") return undefined;
  const e = error as Record<string, unknown>;

  if (typeof e.status === "number") return e.status;
  if (typeof e.statusCode === "number") return e.statusCode;

  const response = e.response;
  if (response && typeof response === "object") {
    const r = response as Record<string, unknown>;
    if (typeof r.status === "number") return r.status;
    if (typeof r.statusCode === "number") return r.statusCode;
  }

  return undefined;
}

/** Extract a Node-style error code (ECONNRESET, etc.) from common shapes. */
export function getErrorCode(error: unknown): string | undefined {
  if (!error || typeof error !== "object") return undefined;
  const e = error as Record<string, unknown>;
  if (typeof e.code === "string") return e.code;
  // undici wraps errors with .cause
  const cause = e.cause;
  if (cause && typeof cause === "object") {
    const c = cause as Record<string, unknown>;
    if (typeof c.code === "string") return c.code;
  }
  return undefined;
}

/** True when the error looks like an intentional abort (NOT retryable). */
export function isAbortError(error: unknown): boolean {
  if (!error || typeof error !== "object") return false;
  const e = error as Record<string, unknown>;
  return (
    e.name === "AbortError" ||
    e.code === "ABORT_ERR" ||
    e.code === "ERR_ABORTED"
  );
}

/**
 * AI-mode default predicate: should this error trigger a retry?
 *
 * Aborts are never retried. Otherwise:
 *   - retryable HTTP statuses (429, 5xx, 408, 409, 425, 529)
 *   - retryable network codes (ECONNRESET, ETIMEDOUT, ...)
 *   - generic "fetch failed" / "network error" messages (last-resort)
 */
export function isRetryableError(error: unknown): boolean {
  if (isAbortError(error)) return false;

  const status = getStatus(error);
  if (typeof status === "number") {
    if (RETRYABLE_STATUS.has(status)) return true;
    // Any 5xx is treated as transient.
    if (status >= 500 && status < 600) return true;
    // 4xx other than the explicit ones above = client error, not retryable.
    if (status >= 400 && status < 500) return false;
  }

  const code = getErrorCode(error);
  if (code && RETRYABLE_NETWORK_CODES.has(code)) return true;

  // Last-resort message sniffing for engines that throw generic Errors.
  if (error instanceof Error) {
    const msg = error.message.toLowerCase();
    if (
      msg.includes("fetch failed") ||
      msg.includes("network error") ||
      msg.includes("socket hang up") ||
      msg.includes("econnreset") ||
      msg.includes("etimedout")
    ) {
      return true;
    }
  }

  return false;
}
