import {
  AbortError,
  RetryError,
  TimeoutError,
  type RetryOptions,
  type RetryableFn,
} from "../types.js";
import { computeBackoff } from "../backoff/strategies.js";
import {
  extractRetryAfterMs,
  isAbortError,
  isRetryableError,
} from "../ai/index.js";
import { combineSignals } from "../utils/abort.js";
import { sleep } from "../utils/sleep.js";

/** Resolved options after defaults + AI-mode adjustments are applied. */
interface ResolvedOptions<T> {
  retries: number;
  delay: number;
  backoff: RetryOptions<T>["backoff"];
  jitter: boolean;
  maxDelay: number;
  totalTimeout: number;
  timeout: number;
  ai: boolean;
  retry?: RetryOptions<T>["retry"];
  signal?: AbortSignal;
  fallback?: RetryOptions<T>["fallback"];
  onRetry?: RetryOptions<T>["onRetry"];
  onSuccess?: RetryOptions<T>["onSuccess"];
  onFail?: RetryOptions<T>["onFail"];
}

function resolveOptions<T>(opts: RetryOptions<T> = {}): ResolvedOptions<T> {
  const ai = opts.ai === true;
  return {
    retries: opts.retries ?? (ai ? 5 : 3),
    delay: opts.delay ?? (ai ? 500 : 200),
    backoff: ai ? "exponential" : (opts.backoff ?? "exponential"),
    jitter: opts.jitter ?? true,
    maxDelay: opts.maxDelay ?? 30_000,
    totalTimeout: opts.totalTimeout ?? 0,
    timeout: opts.timeout ?? 0,
    ai,
    retry: opts.retry,
    signal: opts.signal,
    fallback: opts.fallback,
    onRetry: opts.onRetry,
    onSuccess: opts.onSuccess,
    onFail: opts.onFail,
  };
}

/**
 * Decide whether a given error is retryable for this configuration.
 * User-supplied `retry` predicate overrides everything else (including AI defaults).
 */
async function shouldRetry<T>(
  error: unknown,
  attempt: number,
  resolved: ResolvedOptions<T>,
): Promise<boolean> {
  // Aborts (from external signal) are never retryable.
  if (isAbortError(error)) return false;

  if (resolved.retry) {
    return await resolved.retry(error, attempt);
  }

  if (resolved.ai) {
    return isRetryableError(error);
  }

  // Default (non-AI) mode: retry everything that isn't an explicit abort.
  // This is the conventional behaviour for promise-retry libraries — users
  // opt into smarter classification via `ai: true` or a custom `retry`.
  return true;
}

/**
 * Run `fn` with smart retry & backoff. See {@link RetryOptions} for full options.
 *
 * @example
 * ```ts
 * const data = await retryx(() => fetch("/api").then(r => r.json()));
 * ```
 *
 * @example
 * ```ts
 * const data = await retryx(fetchData, { ai: true });
 * ```
 */
export async function retryx<T>(
  fn: RetryableFn<T>,
  options?: RetryOptions<T>,
): Promise<T> {
  const opts = resolveOptions(options);

  // Validate inputs early — better than mysterious failures later.
  if (typeof fn !== "function") {
    throw new TypeError("retryx: first argument must be a function");
  }
  if (opts.retries < 0 || !Number.isFinite(opts.retries)) {
    throw new RangeError("retryx: `retries` must be a non-negative number");
  }

  const startTime = Date.now();
  const errors: unknown[] = [];

  // Build the deadline signal: combines user signal + total-timeout (if any).
  // We attach this once for the whole operation, NOT per attempt.
  const totalDeadlineController = new AbortController();
  let totalDeadlineTimer: ReturnType<typeof setTimeout> | undefined;
  if (opts.totalTimeout > 0) {
    totalDeadlineTimer = setTimeout(() => {
      totalDeadlineController.abort(new TimeoutError("Total timeout exceeded"));
    }, opts.totalTimeout);
    // Don't keep the Node process alive on this timer.
    if (typeof totalDeadlineTimer === "object" && totalDeadlineTimer !== null) {
      const t = totalDeadlineTimer as { unref?: () => void };
      t.unref?.();
    }
  }

  try {
    for (let attempt = 0; attempt <= opts.retries; attempt++) {
      // Per-attempt signal: user signal + total-timeout signal + per-attempt timeout.
      const perAttemptController = new AbortController();
      let perAttemptTimer: ReturnType<typeof setTimeout> | undefined;
      if (opts.timeout > 0) {
        perAttemptTimer = setTimeout(() => {
          perAttemptController.abort(new TimeoutError("Attempt timed out"));
        }, opts.timeout);
        if (typeof perAttemptTimer === "object" && perAttemptTimer !== null) {
          const t = perAttemptTimer as { unref?: () => void };
          t.unref?.();
        }
      }

      const { signal: attemptSignal, cancel: cancelAttemptSignal } =
        combineSignals([
          opts.signal,
          totalDeadlineController.signal,
          perAttemptController.signal,
        ]);

      // Bail-out check before invoking `fn`.
      if (opts.signal?.aborted) {
        throw new AbortError("Aborted before attempt");
      }
      if (totalDeadlineController.signal.aborted) {
        throw new TimeoutError("Total timeout exceeded");
      }

      try {
        const result = await fn({ attempt, signal: attemptSignal });

        // Success — clean up timers and run onSuccess.
        if (perAttemptTimer) clearTimeout(perAttemptTimer);
        cancelAttemptSignal();

        if (opts.onSuccess) {
          // Hooks shouldn't break the result; swallow hook errors silently.
          try {
            await opts.onSuccess(result, attempt);
          } catch {
            /* hook errors are intentionally swallowed */
          }
        }

        return result;
      } catch (error) {
        if (perAttemptTimer) clearTimeout(perAttemptTimer);
        cancelAttemptSignal();

        // External user-signal abort = give up immediately, no retry.
        if (opts.signal?.aborted) {
          errors.push(error);
          throw new AbortError("Aborted by signal");
        }

        // Total-timeout deadline fired — give up immediately.
        if (totalDeadlineController.signal.aborted) {
          errors.push(error);
          throw new TimeoutError("Total timeout exceeded");
        }

        // Convert per-attempt timeout into a retryable TimeoutError.
        let normalizedError = error;
        if (perAttemptController.signal.aborted && isAbortError(error)) {
          normalizedError = new TimeoutError(
            `Attempt ${attempt} timed out after ${opts.timeout}ms`,
          );
        }

        errors.push(normalizedError);

        // Last attempt? Don't retry — fall through to the failure handler.
        if (attempt >= opts.retries) {
          throw normalizedError;
        }

        // Predicate decides retryability (AbortErrors from user signal already filtered above).
        const retryable = await shouldRetry(normalizedError, attempt, opts);
        if (!retryable) {
          throw normalizedError;
        }

        // Compute the delay. AI mode: honor Retry-After if present.
        const retryAfterMs = opts.ai
          ? extractRetryAfterMs(normalizedError)
          : undefined;

        let nextDelay = computeBackoff({
          attempt,
          delay: opts.delay,
          backoff: opts.backoff ?? "exponential",
          maxDelay: opts.maxDelay,
          jitter: opts.jitter,
          retryAfterMs,
        });

        // Don't sleep past the total-timeout budget.
        if (opts.totalTimeout > 0) {
          const elapsed = Date.now() - startTime;
          const remaining = opts.totalTimeout - elapsed;
          if (remaining <= 0) {
            throw new TimeoutError("Total timeout exceeded");
          }
          if (nextDelay > remaining) nextDelay = remaining;
        }

        // onRetry hook — return false to cancel.
        if (opts.onRetry) {
          let hookResult: void | false = undefined;
          try {
            hookResult = (await opts.onRetry(
              normalizedError,
              attempt,
              nextDelay,
            )) as void | false;
          } catch {
            /* hook errors are swallowed */
          }
          if (hookResult === false) {
            throw normalizedError;
          }
        }

        // Sleep — combined signal so abort/total-timeout interrupts the wait.
        const { signal: sleepSignal, cancel: cancelSleepSignal } =
          combineSignals([opts.signal, totalDeadlineController.signal]);
        try {
          await sleep(nextDelay, sleepSignal);
        } catch (sleepErr) {
          // Sleep was interrupted — surface the right error.
          cancelSleepSignal();
          if (opts.signal?.aborted) throw new AbortError("Aborted by signal");
          if (totalDeadlineController.signal.aborted) {
            throw new TimeoutError("Total timeout exceeded");
          }
          throw sleepErr;
        }
        cancelSleepSignal();
      }
    }

    // Unreachable — the loop always exits via return or throw.
    /* istanbul ignore next */
    throw new RetryError("retryx: exhausted retries", errors);
  } catch (finalError) {
    // Run onFail hook (best-effort).
    if (opts.onFail) {
      try {
        await opts.onFail(finalError, errors.length);
      } catch {
        /* hook errors swallowed */
      }
    }

    // Fallback path — suppresses the error.
    if (opts.fallback !== undefined) {
      if (typeof opts.fallback === "function") {
        return await (opts.fallback as (error: unknown) => T | Promise<T>)(
          finalError,
        );
      }
      return opts.fallback as T;
    }

    // If we accumulated multiple errors, wrap them. Otherwise rethrow as-is so
    // users keep their original error type/stack.
    //
    // Special case: TimeoutError / AbortError are surfaced directly (even if
    // multiple errors were collected) because the user cares more about "we hit
    // the deadline" than about the underlying retry-time errors. Those are still
    // accessible via err.cause if we wanted, but the surface type matters most.
    if (
      finalError instanceof TimeoutError ||
      finalError instanceof AbortError
    ) {
      throw finalError;
    }

    if (errors.length > 1) {
      throw new RetryError(
        `retryx: failed after ${errors.length} attempts: ${
          finalError instanceof Error ? finalError.message : String(finalError)
        }`,
        errors,
      );
    }
    throw finalError;
  } finally {
    if (totalDeadlineTimer) clearTimeout(totalDeadlineTimer);
  }
}
