/**
 * Combine multiple AbortSignals into one. The returned signal aborts as soon
 * as any input signal aborts. Returns a `cancel` function to detach listeners
 * (important to avoid leaks on long-lived parent signals).
 *
 * We don't rely on `AbortSignal.any()` because it's only available in Node 20+
 * and modern browsers — this lib targets Node >= 14.
 */
export function combineSignals(signals: (AbortSignal | undefined)[]): {
  signal: AbortSignal;
  cancel: () => void;
} {
  const real = signals.filter((s): s is AbortSignal => !!s);
  const controller = new AbortController();

  // Already aborted?
  for (const s of real) {
    if (s.aborted) {
      // Forward reason if available (Node 18+, modern browsers).
      const reason = (s as { reason?: unknown }).reason;
      controller.abort(reason);
      return { signal: controller.signal, cancel: () => {} };
    }
  }

  const listeners: Array<{ signal: AbortSignal; handler: () => void }> = [];

  for (const s of real) {
    const handler = () => {
      const reason = (s as { reason?: unknown }).reason;
      controller.abort(reason);
    };
    s.addEventListener("abort", handler, { once: true });
    listeners.push({ signal: s, handler });
  }

  const cancel = () => {
    for (const { signal, handler } of listeners) {
      signal.removeEventListener("abort", handler);
    }
  };

  return { signal: controller.signal, cancel };
}
