import type { BackoffStrategy } from "../types.js";

export interface BackoffParams {
  /** 0-indexed attempt that just failed. The next sleep precedes attempt N+1. */
  attempt: number;
  /** Initial / base delay in ms. */
  delay: number;
  /** Backoff strategy. */
  backoff: BackoffStrategy;
  /** Cap on the returned delay. */
  maxDelay: number;
  /** When true, apply full jitter: random(0, computed). */
  jitter: boolean;
  /**
   * Optional override delay (e.g. from a Retry-After header). When provided,
   * this is used directly (still capped by maxDelay) and the backoff strategy
   * is bypassed. Jitter is NOT applied to server-instructed delays.
   */
  retryAfterMs?: number;
}

/**
 * Compute the delay before the next retry attempt.
 *
 * Strategies:
 *   exponential: delay * 2^attempt
 *   linear:      delay * (attempt + 1)
 *   fixed:       delay
 *
 * Then capped at `maxDelay` and optionally full-jittered.
 *
 * If `retryAfterMs` is set, the server-instructed wait is used as-is (capped).
 */
export function computeBackoff(params: BackoffParams): number {
  const { attempt, delay, backoff, maxDelay, jitter, retryAfterMs } = params;

  // Server told us how long to wait — respect it, no jitter.
  if (typeof retryAfterMs === "number" && retryAfterMs >= 0) {
    return Math.min(retryAfterMs, maxDelay);
  }

  let raw: number;
  switch (backoff) {
    case "exponential":
      // 2^attempt with overflow protection (attempt=30 already overflows reasonable delays).
      raw = delay * Math.pow(2, Math.min(attempt, 30));
      break;
    case "linear":
      raw = delay * (attempt + 1);
      break;
    case "fixed":
      raw = delay;
      break;
    default:
      raw = delay;
  }

  const capped = Math.min(raw, maxDelay);

  if (jitter) {
    // Full jitter: random(0, capped). Best-known strategy against thundering herd.
    return Math.floor(Math.random() * capped);
  }

  return capped;
}
